const body = $input.first().json.body;

const required = ['meeting_id', 'meeting_title', 'meeting_date', 'transcript', 'participants'];

const missing = required.filter(f => !body[f] || String(body[f]).trim() === '');

if (missing.length > 0) {
  throw new Error(`VALIDATION_ERROR: Missing required fields: ${missing.join(', ')}`);
}

if (!Array.isArray(body.participants) || body.participants.length === 0) {
  throw new Error('VALIDATION_ERROR: participants must be a non-empty array');
}

if (body.transcript.length < 100) {
  throw new Error('VALIDATION_ERROR: Transcript too short to process (min 100 chars)');
}

// Normalize participant emails
const normalizedParticipants = body.participants.map(p => ({
  name: (p.name || '').trim(),
  email: (p.email || '').toLowerCase().trim(),
  role: p.role || 'attendee'
})).filter(p => p.email.includes('@'));

// Normalize date
const meetingDate = new Date(body.meeting_date);
if (isNaN(meetingDate.getTime())) {
  throw new Error('VALIDATION_ERROR: Invalid meeting_date format');
}

return [{
  json: {
    ...body,
    meeting_id: body.meeting_id.toString().trim(),
    meeting_title: body.meeting_title.trim(),
    meeting_date: meetingDate.toISOString(),
    participants: normalizedParticipants,
    participant_emails: normalizedParticipants.map(p => p.email),
    organizer_email: normalizedParticipants.find(p => p.role === 'organizer')?.email
      || normalizedParticipants[0].email,
    transcript: body.transcript.trim(),
    platform: (body.platform || 'unknown').toLowerCase(),
    duration_minutes: parseInt(body.duration_minutes) || 0,
    validated_at: new Date().toISOString()
  }
}];

const data = $input.first().json;
let raw = data.transcript;

// Remove platform-specific timestamp patterns
raw = raw.replace(/\[?\d{1,2}:\d{2}(:\d{2})?\]?/g, '');

// Remove filler words and disfluencies
raw = raw.replace(/\b(um|uh|er|ah|like,|you know,)\b/gi, '');

// Collapse multiple whitespace/newlines
raw = raw.replace(/[ \t]+/g, ' ')
         .replace(/\n{3,}/g, '\n\n')
         .trim();

// Extract speaker turns for context
const speakerPattern = /^([A-Z][a-z]+ [A-Z][a-z]+):\s*/m;
const speakers = [...new Set(
  raw.match(/^([A-Z][a-z]+ [A-Z][a-z]+):/gm)
     ?.map(s => s.replace(':', '').trim()) || []
)];

// Chunk if transcript exceeds 80k characters
const MAX_CHARS = 80000;
let chunks = [];
if (raw.length > MAX_CHARS) {
  for (let i = 0; i < raw.length; i += MAX_CHARS) {
    chunks.push(raw.substring(i, i + MAX_CHARS));
  }
} else {
  chunks = [raw];
}

// Word count for analytics
const wordCount = raw.split(/\s+/).length;

return [{
  json: {
    ...data,
    transcript_cleaned: raw,
    transcript_chunks: chunks,
    chunk_count: chunks.length,
    is_chunked: chunks.length > 1,
    detected_speakers: speakers,
    word_count: wordCount,
    char_count: raw.length,
    preprocessed_at: new Date().toISOString()
  }
}];

const data = $input.first().json;
const date = new Date(data.meeting_date);

const participantList = data.participants
  .map(p => `${p.name} (${p.email})`)
  .join('; ');

const runId = `run_${data.meeting_id}_${Date.now()}`;

const dateFormatted = date.toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

return [{
  json: {
    ...data,
    run_id: runId,
    meeting_date_formatted: dateFormatted,
    meeting_week: `${getISOWeek(date)}-${date.getFullYear()}`,
    meeting_month: `${date.getFullYear()}-${String(date.getMonth()+1).padStart(2,'0')}`,
    participant_list_formatted: participantList,
    participant_count: data.participants.length,
    notion_database_id: `{{$env.NOTION_MEETINGS_DB_ID}}`,
    asana_project_id: `{{$env.ASANA_PROJECT_ID}}`,
    slack_channel_id: `{{$env.SLACK_MEETINGS_CHANNEL}}`
  }
}];

function getISOWeek(date) {
  const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
  d.setUTCDate(d.getUTCDate() + 4 - (d.getUTCDay() || 7));
  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
  return Math.ceil((((d - yearStart) / 86400000) + 1) / 7);
}

