const data = $input.first().json;

let parsed;

// ✅ Case 1: Already structured (your current case)
if (data.output) {
  parsed = data.output;
}

// ✅ Case 2: Claude text response
else if (data.content?.[0]?.text) {
  let rawText = data.content[0].text;
  rawText = cleanJSON(rawText);
  parsed = safeParse(rawText);
}

// ✅ Case 3: OpenAI text response
else if (data.choices?.[0]?.message?.content) {
  let rawText = data.choices[0].message.content;
  rawText = cleanJSON(rawText);
  parsed = safeParse(rawText);
}

// ❌ Unknown structure
else {
  throw new Error('PARSE_ERROR: Unexpected AI response structure');
}

// Schema validation
const requiredFields = [
  'meeting_summary',
  'key_topics',
  'decisions',
  'action_items',
  'risks_or_blockers',
  'followups'
];

const missingFields = requiredFields.filter(f => !(f in parsed));

if (missingFields.length > 0) {
  return [{
    json: {
      ...data,
      parse_success: false,
      parse_error: `Missing fields: ${missingFields.join(', ')}`
    }
  }];
}

// Enrich action items
const enrichedActions = (parsed.action_items || []).map((item, i) => ({
  task_id: `task_${data.meeting_id}_${String(i + 1).padStart(3, '0')}`,
  task: item.task || '',
  owner: item.owner || 'Unassigned',
  owner_email: resolveEmail(item.owner, data.participants || []),
  deadline: normalizeDeadline(item.deadline, data.meeting_date),
  deadline_raw: item.deadline || 'No deadline set',
  priority: item.priority || 'normal'
}));

return [{
  json: {
    ...data,
    ai_output: { ...parsed, action_items: enrichedActions },
    parse_success: true,
    action_item_count: enrichedActions.length,
    parsed_at: new Date().toISOString()
  }
}];

// ------------------ HELPERS ------------------

function cleanJSON(text) {
  return text
    .replace(/^```(?:json)?\n?/, '')
    .replace(/\n?```$/, '')
    .trim();
}

function safeParse(text) {
  try {
    return JSON.parse(text);
  } catch (e) {
    throw new Error(`PARSE_ERROR: Invalid JSON → ${e.message}`);
  }
}

function resolveEmail(ownerName, participants) {
  if (!ownerName) return '';
  const match = participants.find(p =>
    p.name?.toLowerCase().includes(ownerName.toLowerCase())
  );
  return match?.email || '';
}

function normalizeDeadline(raw, meetingDate) {
  if (!raw) return '';
  const base = new Date(meetingDate);
  const lower = raw.toLowerCase();

  if (lower.includes('tomorrow')) {
    base.setDate(base.getDate() + 1);
    return base.toISOString().split('T')[0];
  }

  if (lower.includes('next week')) {
    base.setDate(base.getDate() + 7);
    return base.toISOString().split('T')[0];
  }

  const iso = new Date(raw);
  return isNaN(iso.getTime())
    ? raw
    : iso.toISOString().split('T')[0];
}

